def perceive(data):
    text = data if isinstance(data, str) else str(data)
    known = ["day", "evening", "night"]
    census = {}
    for line in text.splitlines():
        if ":" not in line:
            continue
        k, v = line.split(":", 1)
        k = k.strip().lower()
        v = v.strip()
        if k in known:
            try:
                census[k] = int(v)
            except (ValueError, TypeError):
                pass
    return {"patients": census} if census else {}
